import React, { useState } from 'react';

const InputArea = ({ currentStep, onSendMessage, isTyping }) => {
  const [inputValue, setInputValue] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (inputValue.trim() && !isTyping) {
      onSendMessage(inputValue);
      setInputValue('');
    }
  };

  if (!currentStep || isTyping) return <div className="h-16" />; // Keep space for typing indicator

  return (
  <div className="w-full">
    {currentStep.type === 'text' || currentStep.type === 'voice_text' ? (
      <form onSubmit={handleSubmit} className="relative">
        <input
          autoFocus
          type="text"
          className="w-full text-center text-xl p-4 border-b-2 border-slate-100 focus:border-emerald-500 outline-none transition-colors bg-transparent text-slate-700"
          placeholder="Type here..."
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
        />
        {currentStep.type === 'voice_text' && (
          <div className="mt-4 flex justify-center">
            <button type="button" className="p-4 bg-emerald-50 rounded-full text-emerald-600 hover:bg-emerald-100 transition-all">
              {/* Mic Icon Placeholder */}
              🎤 Tap to speak
            </button>
          </div>
        )}
      </form>
    ) : currentStep.type === 'choice' ? (
      <div className="flex flex-col gap-3">
        {currentStep.options.map((option) => (
          <button
            key={option}
            onClick={() => onSendMessage(option)}
            className="w-full py-4 px-6 bg-slate-50 hover:bg-emerald-600 hover:text-white text-slate-700 rounded-2xl font-medium transition-all duration-300 transform hover:scale-[1.02]"
          >
            {option}
          </button>
        ))}
      </div>
    ) : null}
  </div>
);
};

export default InputArea;
